using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap the Open-Meteo REST API via HttpClient.
/// Uses constructor injection — the SDK creates an instance per invocation
/// and injects any DI-registered services declared in the constructor.
/// </summary>
[McpServerToolType]
public class WeatherApiTools(HttpClient httpClient, ILogger<WeatherApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get the current weather for a location using latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location (e.g. 47.6062 for Seattle)")] double latitude,
        [Description("Longitude of the location (e.g. -122.3321 for Seattle)")] double longitude,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching weather for ({Lat}, {Lon})", latitude, longitude);

        var url = $"https://api.open-meteo.com/v1/forecast"
                + $"?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m,relative_humidity_2m";

        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(
            await response.Content.ReadAsStreamAsync(cancellationToken), cancellationToken: cancellationToken);

        var current = doc.RootElement.GetProperty("current");
        var units = doc.RootElement.GetProperty("current_units");

        var result = new
        {
            temperature = $"{current.GetProperty("temperature_2m")} {units.GetProperty("temperature_2m")}",
            wind_speed = $"{current.GetProperty("wind_speed_10m")} {units.GetProperty("wind_speed_10m")}",
            humidity = $"{current.GetProperty("relative_humidity_2m")}{units.GetProperty("relative_humidity_2m")}"
        };

        return JsonSerializer.Serialize(result, JsonOptions);
    }

    [McpServerTool, Description("Get a multi-day weather forecast for a location.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        [Description("Number of forecast days (1-7)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        days = Math.Clamp(days, 1, 7);

        var url = $"https://api.open-meteo.com/v1/forecast"
                + $"?latitude={latitude}&longitude={longitude}"
                + $"&daily=temperature_2m_max,temperature_2m_min,precipitation_sum"
                + $"&forecast_days={days}";

        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }
}

